//! GLM-OCR vision-tower forward PoC on SYNTHETIC weights.
//!
//! Proves the sovereign OCR vision encoder (`model_glm_ocr_vit::GlmOcrViT`)
//! runs end-to-end in-process: patch-embed (Conv3d-as-matmul) → 2D-RoPE →
//! `depth` full-attention SwiGLU transformer blocks → post-LayerNorm →
//! Conv2d downsample (2×2) → GLM patch-merger → `[n_merged, out_hidden]`.
//!
//! There is NO `glm-ocr.knot` in R2 yet, and the dense knot is multi-GB, so
//! this PoC mirrors the SSM/whisper synthetic-fixture approach: it fabricates
//! deterministic, fan-in-scaled weights for every `vit_*` tensor the kernel
//! requests (via a `WeightBackend` stub) and feeds a deterministic synthetic
//! patch grid. This exercises the REAL kernel code path at the REAL GLM-OCR
//! config dims (hidden=1024, depth=24, out_hidden=1536) — only the weight
//! VALUES are synthetic. The gate asserts: output shape is correct, all values
//! are finite (no NaN/Inf through 24 residual blocks + downsample + merger),
//! and the output is non-degenerate (rows differ; spread is non-trivial).
//!
//! Next step to go live: encode a real `glm-ocr.knot` (encode-knot.py glm_ocr
//! branch, vision tower included), wire an OCR serving contract that returns
//! TEXT bytes (not token streams) — see `ocr-probe` for the full
//! image→ViT→splice→text-backbone→decode pipeline.
//!
//! Usage:
//!   glm-ocr-synth-poc [--grid-h 4] [--grid-w 4] [--depth 24] [--hidden 1024]

use std::sync::Arc;
use std::time::Instant;

use distributed_inference::loader::{OwnedBytes, WeightBackend};
use distributed_inference::model_glm_ocr_vit::{GlmOcrViT, GlmOcrVitConfig};

/// Deterministic, allocation-on-demand synthetic weight backend.
///
/// Returns f32 little-endian bytes for any `vit_*` tensor name, with the length
/// derived from the GLM-OCR config so the kernel's mat_vec dims line up exactly.
/// Linear weights are filled with a per-element splitmix64 hash scaled to
/// variance ≈ 1/fan_in (keeps activations bounded through deep residual
/// stacks). Norm weights are 1.0; biases are 0.0 — exactly what a sane init
/// looks like, so finite, non-degenerate output is a real signal the forward
/// math is wired correctly.
struct SynthBackend {
    cfg: GlmOcrVitConfig,
}

impl SynthBackend {
    fn new(cfg: GlmOcrVitConfig) -> Self {
        Self { cfg }
    }

    /// (element_count, fan_in_for_scaling, is_norm_or_bias).
    /// `None` → unknown tensor name (kernel asked for something we didn't model).
    fn shape_of(&self, name: &str) -> Option<(usize, usize, Kind)> {
        let c = &self.cfg;
        let h = c.hidden_size;
        let inter = c.intermediate_size;
        let out_h = c.out_hidden_size;
        let m_inter = c.merger_intermediate_size;
        let head_dim = c.head_dim();
        let patch_dim = c.patch_dim();
        let merge_in = h * c.merge_unit();

        // Top-level (non per-block) tensors.
        match name {
            "vit_patch_embed_weight" => return Some((h * patch_dim, patch_dim, Kind::Linear)),
            "vit_patch_embed_bias" => return Some((h, 0, Kind::Bias)),
            "vit_post_layernorm_weight" => return Some((h, 0, Kind::Norm)),
            "vit_downsample_weight" => {
                return Some((out_h * merge_in, merge_in, Kind::Linear))
            }
            "vit_downsample_bias" => return Some((out_h, 0, Kind::Bias)),
            "vit_merger_proj_weight" => return Some((out_h * out_h, out_h, Kind::Linear)),
            "vit_merger_post_norm_weight" => return Some((out_h, 0, Kind::Norm)),
            "vit_merger_post_norm_bias" => return Some((out_h, 0, Kind::Bias)),
            "vit_merger_gate_weight" => return Some((m_inter * out_h, out_h, Kind::Linear)),
            "vit_merger_up_weight" => return Some((m_inter * out_h, out_h, Kind::Linear)),
            "vit_merger_down_weight" => return Some((out_h * m_inter, m_inter, Kind::Linear)),
            _ => {}
        }

        // Per-block tensors: vit_blk_{i}_<suffix>.
        let rest = name.strip_prefix("vit_blk_")?;
        let (_idx, suffix) = rest.split_once('_')?;
        let qkv_dim = 3 * h;
        match suffix {
            "norm1_weight" | "norm2_weight" => Some((h, 0, Kind::Norm)),
            "attn_qkv_weight" => Some((qkv_dim * h, h, Kind::Linear)),
            "attn_qkv_bias" => Some((qkv_dim, 0, Kind::Bias)),
            "attn_q_norm_weight" | "attn_k_norm_weight" => Some((head_dim, 0, Kind::Norm)),
            "attn_proj_weight" => Some((h * h, h, Kind::Linear)),
            "mlp_gate_weight" | "mlp_up_weight" => Some((inter * h, h, Kind::Linear)),
            "mlp_gate_bias" | "mlp_up_bias" => Some((inter, 0, Kind::Bias)),
            "mlp_down_weight" => Some((h * inter, inter, Kind::Linear)),
            "mlp_down_bias" => Some((h, 0, Kind::Bias)),
            _ => None,
        }
    }
}

enum Kind {
    Linear,
    Norm,
    Bias,
}

/// splitmix64 → uniform f32 in (-1, 1).
fn rand_unit(state: &mut u64) -> f32 {
    *state = state.wrapping_add(0x9E37_79B9_7F4A_7C15);
    let mut z = *state;
    z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
    z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
    z ^= z >> 31;
    // top 24 bits → [0,1), then map to (-1,1).
    let u = (z >> 40) as f32 / (1u32 << 24) as f32;
    2.0 * u - 1.0
}

/// FNV-1a 64-bit name hash → per-tensor seed (reproducible across runs).
fn name_seed(name: &str) -> u64 {
    let mut h = 0xCBF2_9CE4_8422_2325u64;
    for b in name.bytes() {
        h ^= b as u64;
        h = h.wrapping_mul(0x0000_0100_0000_01B3);
    }
    h | 1
}

impl WeightBackend for SynthBackend {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        let (n, fan_in, kind) = self
            .shape_of(name)
            .ok_or_else(|| format!("synth backend: unmodeled tensor {name}"))?;
        let mut buf = Vec::with_capacity(n * 4);
        let mut state = name_seed(name);
        // variance 1/fan_in ⇒ uniform[-1,1] scaled by sqrt(3/fan_in).
        let scale = if fan_in > 0 {
            (3.0f32 / fan_in as f32).sqrt()
        } else {
            0.0
        };
        for _ in 0..n {
            let v = match kind {
                Kind::Linear => rand_unit(&mut state) * scale,
                Kind::Norm => 1.0,
                Kind::Bias => 0.0,
            };
            buf.extend_from_slice(&v.to_le_bytes());
        }
        Ok(OwnedBytes::Owned(Arc::new(buf)))
    }

    fn has_tensor(&self, name: &str) -> bool {
        self.shape_of(name).is_some()
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
    // tensor_info default None ⇒ fetch_f32 treats bytes as f32. Correct here.
}

struct Args {
    grid_h: usize,
    grid_w: usize,
    depth: usize,
    hidden: usize,
}

fn parse_args() -> Args {
    let mut a = Args {
        grid_h: 4,
        grid_w: 4,
        depth: 24,
        hidden: 1024,
    };
    let raw: Vec<String> = std::env::args().skip(1).collect();
    let mut i = 0;
    while i < raw.len() {
        let need = |i: usize| -> &String {
            raw.get(i + 1).unwrap_or_else(|| {
                eprintln!("missing value for {}", raw[i]);
                std::process::exit(2);
            })
        };
        match raw[i].as_str() {
            "--grid-h" => a.grid_h = need(i).parse().unwrap(),
            "--grid-w" => a.grid_w = need(i).parse().unwrap(),
            "--depth" => a.depth = need(i).parse().unwrap(),
            "--hidden" => a.hidden = need(i).parse().unwrap(),
            "-h" | "--help" => {
                eprintln!("usage: glm-ocr-synth-poc [--grid-h N] [--grid-w N] [--depth N] [--hidden N]");
                std::process::exit(0);
            }
            other => {
                eprintln!("unknown arg {other}");
                std::process::exit(2);
            }
        }
        i += 2;
    }
    a
}

fn main() {
    let args = parse_args();
    let mut cfg = GlmOcrVitConfig::default();
    cfg.depth = args.depth;
    cfg.hidden_size = args.hidden;
    // keep num_heads dividing hidden; default 16 divides 1024. If hidden is
    // overridden, fall back to a head_dim of 64 where possible.
    if cfg.hidden_size % cfg.num_heads != 0 {
        cfg.num_heads = (cfg.hidden_size / 64).max(1);
    }

    let patch_dim = cfg.patch_dim();
    let n = args.grid_h * args.grid_w;
    let n_merged = (args.grid_h / cfg.spatial_merge_size) * (args.grid_w / cfg.spatial_merge_size);

    eprintln!("glm-ocr-synth-poc: SYNTHETIC weights (no knot) — REAL kernel forward path");
    eprintln!(
        "  config: hidden={} depth={} heads={} head_dim={} inter={} out_hidden={} merger_inter={}",
        cfg.hidden_size,
        cfg.depth,
        cfg.num_heads,
        cfg.head_dim(),
        cfg.intermediate_size,
        cfg.out_hidden_size,
        cfg.merger_intermediate_size,
    );
    eprintln!(
        "  input : grid {}x{} = {n} patches, patch_dim={patch_dim} → expect {n_merged} merged tokens",
        args.grid_h, args.grid_w
    );

    // Deterministic synthetic patch grid (unit-variance pixels).
    let mut pix = vec![0.0f32; n * patch_dim];
    let mut st = 0xDEAD_BEEF_CAFE_F00Du64;
    for v in pix.iter_mut() {
        *v = rand_unit(&mut st);
    }

    let backend: Arc<dyn WeightBackend> = Arc::new(SynthBackend::new(cfg.clone()));
    let vit = GlmOcrViT::new(cfg.clone(), backend);

    let t = Instant::now();
    let out = match vit.forward(&pix, args.grid_h, args.grid_w) {
        Ok(o) => o,
        Err(e) => {
            println!("\nFAIL: ViT forward errored: {e}");
            std::process::exit(1);
        }
    };
    let dt = t.elapsed().as_secs_f32();

    let out_h = cfg.out_hidden_size;
    let got_tokens = out.len() / out_h;
    let nan = out.iter().filter(|x| x.is_nan()).count();
    let inf = out.iter().filter(|x| x.is_infinite()).count();
    let amax = out.iter().fold(0.0f32, |a, &b| a.max(b.abs()));
    let mean = out.iter().sum::<f32>() / out.len() as f32;
    let var = out.iter().map(|&x| (x - mean) * (x - mean)).sum::<f32>() / out.len() as f32;

    // Non-degenerate: distinct rows (merged tokens shouldn't collapse to one).
    let mut distinct_rows = 1usize;
    if got_tokens > 1 {
        let r0 = &out[0..out_h];
        for t in 1..got_tokens {
            let rt = &out[t * out_h..(t + 1) * out_h];
            let diff: f32 = r0.iter().zip(rt).map(|(a, b)| (a - b).abs()).sum();
            if diff > 1e-3 {
                distinct_rows += 1;
            }
        }
    }

    println!("\n── glm-ocr-synth-poc result ──");
    println!("  forward wall:     {dt:.3}s");
    println!("  output shape:     [{got_tokens}, {out_h}]  (expected [{n_merged}, {out_h}])");
    println!("  finite:           nan={nan} inf={inf}");
    println!("  |out|max:         {amax:.4}");
    println!("  mean / var:       {mean:.4} / {var:.4}");
    println!("  distinct rows:    {distinct_rows}/{got_tokens}");

    let shape_ok = got_tokens == n_merged && out_h == cfg.out_hidden_size;
    let finite_ok = nan == 0 && inf == 0 && amax > 0.0 && amax.is_finite();
    let nondegen_ok = var > 1e-9 && distinct_rows >= got_tokens.min(2);

    if shape_ok && finite_ok && nondegen_ok {
        println!(
            "\nPASS: GLM-OCR vision tower forward ran end-to-end on synthetic weights \
             (real kernel path, finite + non-degenerate output)."
        );
        std::process::exit(0);
    }
    println!(
        "\nFAIL: shape_ok={shape_ok} finite_ok={finite_ok} nondegen_ok={nondegen_ok}"
    );
    std::process::exit(1);
}
